/// Indicates a specific risk identified in the Resilience Hub assessment and
/// the corresponding recommendation provided to address that risk.
///
/// The assessment summary generated by large language models (LLMs) on Amazon
/// Bedrock are only suggestions.
/// The current level of generative AI technology is not perfect and LLMs are
/// not infallible.
/// Bias and incorrect answers, although rare, should be expected. Review each
/// recommendation in the assessment summary before you use the output from an
/// LLM.
///
/// This property is available only in the US East (N. Virginia) Region.
pub const AssessmentRiskRecommendation = struct {
    /// Indicates the Application Components (AppComponents) that were assessed as
    /// part of the
    /// assessment and are associated with the identified risk and recommendation.
    ///
    /// This property is available only in the US East (N. Virginia) Region.
    app_components: ?[]const []const u8 = null,

    /// Indicates the recommendation provided by the Resilience Hub to address the
    /// identified
    /// risks in the application.
    ///
    /// This property is available only in the US East (N. Virginia) Region.
    recommendation: ?[]const u8 = null,

    /// Indicates the description of the potential risk identified in the
    /// application as part of the Resilience Hub assessment.
    ///
    /// This property is available only in the US East (N. Virginia) Region.
    risk: ?[]const u8 = null,

    pub const json_field_names = .{
        .app_components = "appComponents",
        .recommendation = "recommendation",
        .risk = "risk",
    };
};
